反转链表 <pre><code>ListNode *reverse(ListNode *head) {
    ListNode *newHead = NULL;
    ListNode *tmp, *cur = head;
    while (head != NULL) {
        tmp = head-&gt;next;
        head-&gt;next = newHead;
        newHead = head;
        head = tmp;
    }
    return newHead;
}
